>
  <div>📄 Code Copy</div>
</button>
<span id="copy1" style={{ marginLeft: "10px", color: "green" }}></span>

Header를 모든 페이지에 적용합니다. 따라서 layout에 Header 컴포넌트를 넣어줍니다.

```javascript title="src/app/layout.js"
import { Inter, Manrope } from "next/font/google";
import "./globals.css";
import { cx } from "@/src/utils";
import Header from "@/src/components/Header";

const inter = Inter({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-in",
});
const manrope = Manrope({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-mr",
});

export const metadata = {
  title: "Create Next App",
  description: "Generated by create next app",
};

export default function RootLayout({ children }) {
  return (
    <html lang="en">
      <body
        className={cx(
          inter.variable,
          manrope.variable,
          "font-mr bg-light dark:bg-dark"
        )}
      >
        <Header />
        {children}
      </body>
    </html>
  );
}
```

